using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _service = null!;

    [TestInitialize]
    public void Setup()
    {
        _service = new OrderService();
    }

    // --- CreateOrder: validation ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 1 }
        };

        Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    // --- CreateOrder: happy-path ---

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Gadget", Price = 25.00m, Quantity = 3 }
        };

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(75.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_SumsTotalsCorrectly()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 10.00m, Quantity = 2 },
            new() { ProductName = "B", Price = 5.50m, Quantity = 4 }
        };

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(42.00m, order.Total); // 20 + 22
    }

    [TestMethod]
    public void CreateOrder_SetsCustomerIdAndItems()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        var order = _service.CreateOrder("cust-42", items);

        Assert.AreEqual("cust-42", order.CustomerId);
        Assert.AreSame(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueIds()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "X", Price = 1.00m, Quantity = 1 }
        };

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;

        var order = _service.CreateOrder("cust-1", new List<OrderItem>
        {
            new() { ProductName = "W", Price = 1.00m, Quantity = 1 }
        });

        var after = DateTime.UtcNow;

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            "CreatedAt should be between the before and after timestamps.");
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsOrder()
    {
        var created = _service.CreateOrder("cust-1", new List<OrderItem>
        {
            new() { ProductName = "W", Price = 5.00m, Quantity = 1 }
        });

        var found = _service.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistingId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("unknown");

        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "W", Price = 1.00m, Quantity = 1 }
        };

        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-A", items);
        _service.CreateOrder("cust-B", items);

        var result = _service.GetOrdersByCustomer("cust-A");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-A"));
    }
}

